#include<bits/stdc++.h>
#include<ext/pb_ds/assoc_container.hpp>
#include<ext/pb_ds/tree_policy.hpp>
using namespace __gnu_pbds;
using namespace std;
struct node
{
    int v,id;
    node(int a,int b):v(a),id(b){}
    bool operator>(const node&b)const
    {
        return (v==b.v?id>b.id:v>b.v);
    }
};
tree<node,null_type,greater<node>,rb_tree_tag,tree_order_statistics_node_update> t,te;
int main()
{
    int n,m,s=0;
    scanf("%d%d",&n,&m);
    long long ans=0;
    while(n--)
    {
        char ch;
        cin>>ch;
        int x;
        scanf("%d",&x);
        if(ch=='I')
        {
            x+=s;
            if(x>=m)
            {
                t.insert((node){x,n});
            }
        }
        else if(ch=='A')
        {
            m-=x;
            s-=x;
        }
        else if(ch=='S')
        {
            m+=x;
            s+=x;
            t.split((node){m,-1},te);
            ans+=te.size();
        }
        else if(ch=='F')
        {
            if(x>t.size())
            {
                printf("-1\n");
            }
            else
            {
                printf("%d\n",t.find_by_order(x-1)->v-s);
            }
        }
    }
    printf("%lld",ans);
    return 0;
}
